// Получаем код от Агента
const query = $('When Executed by Another Workflow').first().json.error_code;

// Получаем текст мануала. 
// ВНИМАНИЕ: Замени 'Extract from File' на имя твоей ноды, которая выдает текст
const textData = $input.first().json.text; 

if (!query || !textData) {
  return { result: "Сбой: текст мануала или код не получены." };
}

// Защита от дефисов и спецсимволов в коде (чтобы regex не сломался)
const escapeRegex = (string) => string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
const regex = new RegExp(escapeRegex(query), 'gi');

let match;
let results = [];
let count = 0;

// Ищем до 3 совпадений, берем по 400 символов (около 50 слов) до и после
while ((match = regex.exec(textData)) !== null && count < 3) {
    let start = Math.max(0, match.index - 400);
    let end = Math.min(textData.length, match.index + query.length + 400);
    let snippet = textData.substring(start, end);

    results.push(`[Совпадение ${count + 1}]:\n...${snippet}...`);
    count++;
}

if (count === 0) {
    return { result: `Прямых упоминаний кода ${query} не найдено. Используй векторный поиск.` };
}

return { result: `Найдены точные совпадения для ${query}:\n\n` + results.join('\n\n') };
